package com.themuffinman.app.vision.service;
import com.themuffinman.app.vision.model.VisionConversation; import org.springframework.stereotype.Service;
@Service public class VisionDeleteAvailabilityExceptionExecutionAdapter implements VisionCapabilityExecutionAdapter { private final VisionBusinessAvailabilityMutationService service; public VisionDeleteAvailabilityExceptionExecutionAdapter(VisionBusinessAvailabilityMutationService s){service=s;} public String capabilityId(){return "delete_availability_exception";} public VisionExecutionResult execute(VisionConversation c){try{service.deleteException(c.getSlotData(),c.getOwner());return VisionExecutionResult.executedAction(capabilityId());}catch(RuntimeException e){return VisionExecutionResult.blocked("The availability exception could not be deleted.");}} }
